{
  "title": "Chocolate Chip Cookies",
  "description": "Classic homemade chocolate chip cookies",
  "yield": 24,
  "prepTimeMinutes": 15,
  "cookTimeMinutes": 12,
  "source": "https://example.com/recipes",
  "originalImageUrl": "https://example.com/images/cookies.jpg",
  "ingredients": [
    {
      "sortOrder": 1,
      "quantity": 2.25,
      "unit": "cup",
      "item": "all-purpose flour",
      "preparation": null,
      "rawText": "2 1/4 cups all-purpose flour"
    },
    {
      "sortOrder": 2,
      "quantity": 1,
      "unit": "tsp",
      "item": "baking soda",
      "preparation": null,
      "rawText": "1 tsp baking soda"
    },
    {
      "sortOrder": 3,
      "quantity": 1,
      "unit": "tsp",
      "item": "salt",
      "preparation": null,
      "rawText": "1 tsp salt"
    },
    {
      "sortOrder": 4,
      "quantity": 1,
      "unit": "cup",
      "item": "butter",
      "preparation": "softened",
      "rawText": "1 cup butter, softened"
    },
    {
      "sortOrder": 5,
      "quantity": 0.75,
      "unit": "cup",
      "item": "granulated sugar",
      "preparation": null,
      "rawText": "3/4 cup granulated sugar"
    },
    {
      "sortOrder": 6,
      "quantity": 0.75,
      "unit": "cup",
      "item": "packed brown sugar",
      "preparation": null,
      "rawText": "3/4 cup packed brown sugar"
    },
    {
      "sortOrder": 7,
      "quantity": 2,
      "unit": "piece",
      "item": "eggs",
      "preparation": null,
      "rawText": "2 eggs"
    },
    {
      "sortOrder": 8,
      "quantity": 2,
      "unit": "cup",
      "item": "chocolate chips",
      "preparation": null,
      "rawText": "2 cups chocolate chips"
    }
  ],
  "instructions": [
    {
      "stepNumber": 1,
      "instruction": "Preheat oven to 375°F",
      "rawText": "Preheat oven to 375°F"
    },
    {
      "stepNumber": 2,
      "instruction": "In small bowl, combine flour, baking soda and salt",
      "rawText": "In small bowl, combine flour, baking soda and salt"
    },
    {
      "stepNumber": 3,
      "instruction": "In large bowl, beat butter and sugars until creamy",
      "rawText": "In large bowl, beat butter and sugars until creamy"
    },
    {
      "stepNumber": 4,
      "instruction": "Add eggs to butter mixture and mix well",
      "rawText": "Add eggs to butter mixture and mix well"
    },
    {
      "stepNumber": 5,
      "instruction": "Gradually stir in flour mixture",
      "rawText": "Gradually stir in flour mixture"
    },
    {
      "stepNumber": 6,
      "instruction": "Stir in chocolate chips",
      "rawText": "Stir in chocolate chips"
    },
    {
      "stepNumber": 7,
      "instruction": "Drop rounded tablespoons onto ungreased baking sheets",
      "rawText": "Drop rounded tablespoons onto ungreased baking sheets"
    },
    {
      "stepNumber": 8,
      "instruction": "Bake for 9 to 12 minutes or until golden brown",
      "rawText": "Bake for 9 to 12 minutes or until golden brown"
    }
  ]
}
